    PROCEDURE FillData IS
    BEGIN
        FOR i IN 1..7 LOOP
            INSERT INTO Cruises (cr_id, c_name, c_ship, c_departure_date, c_return_date) 
            VALUES (cruises_seq.NEXTVAL, 'Cruise ' || i, 'Ship ' || i, SYSDATE + i, SYSDATE + 10 + i);

            FOR j IN 1..3 LOOP
                INSERT INTO Ports(p_id, p_name, p_country, p_capacity, cr_id)
                VALUES(ports_seq.NEXTVAL, 'Port ' || j || ' of Cruise ' || i, 'Country ' || j, 10000 + j, cruises_seq.CURRVAL);
            END LOOP;
        END LOOP;

        COMMIT;
    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            RAISE_APPLICATION_ERROR(-20001, 'Failed to fill tables with data', TRUE);
    END FillData;

    PROCEDURE ClearData IS
    BEGIN
        DELETE FROM Ports;
        DELETE FROM Cruises;
        COMMIT;
    EXCEPTION
